import{_ as a,o as n,c as t,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Scheduling Games","description":"","frontmatter":{},"headers":[],"relativePath":"schedule/scheduling-games.md","filePath":"schedule/scheduling-games.md"}'),s={name:"schedule/scheduling-games.md"};function i(d,e,l,r,g,h){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="scheduling-games" tabindex="-1">Scheduling Games <a class="header-anchor" href="#scheduling-games" aria-label="Permalink to &quot;Scheduling Games&quot;">​</a></h1><p>Pre-scheduling games saves time on game day and keeps your season record organized.</p><h2 id="adding-a-game" tabindex="-1">Adding a Game <a class="header-anchor" href="#adding-a-game" aria-label="Permalink to &quot;Adding a Game&quot;">​</a></h2><ol><li>Navigate to <strong>Schedule</strong></li><li>Tap <strong>+ Game</strong></li><li>Fill in the details: <ul><li><strong>Opponent</strong> — select from saved opponents or tap <strong>New Opponent</strong> to add</li><li><strong>Date</strong> — tap to open the date picker</li><li><strong>Time</strong> — optional but useful for the daily schedule view</li><li><strong>Location</strong> — field name or address</li><li><strong>Home or Away</strong> — affects how the score is displayed</li></ul></li><li>Tap <strong>Save</strong></li></ol><p>The game appears on your schedule and in the dashboard upcoming games widget.</p><h2 id="managing-opponents" tabindex="-1">Managing Opponents <a class="header-anchor" href="#managing-opponents" aria-label="Permalink to &quot;Managing Opponents&quot;">​</a></h2><p>Opponents are saved automatically the first time you add them. On subsequent games against the same team select them from your opponent list — this keeps game history organized by opponent.</p><p>Edit or delete saved opponents from <strong>Schedule → Opponents</strong> in the menu.</p><h2 id="game-day-connection" tabindex="-1">Game Day Connection <a class="header-anchor" href="#game-day-connection" aria-label="Permalink to &quot;Game Day Connection&quot;">​</a></h2><p>On game day when you start a game session the app checks for games scheduled for today. Tap the scheduled game to pre-fill the opponent and game details. This links the scoring session to the scheduled game so the result records automatically when you end the session.</p><h2 id="editing-a-scheduled-game" tabindex="-1">Editing a Scheduled Game <a class="header-anchor" href="#editing-a-scheduled-game" aria-label="Permalink to &quot;Editing a Scheduled Game&quot;">​</a></h2><p>Tap any game card on the schedule to open game details. Tap <strong>Edit</strong> to modify date, time, opponent, or location. You can edit scheduled games up until the game session is started.</p><h2 id="cancellations-and-postponements" tabindex="-1">Cancellations and Postponements <a class="header-anchor" href="#cancellations-and-postponements" aria-label="Permalink to &quot;Cancellations and Postponements&quot;">​</a></h2><p>To mark a game as cancelled or postponed open the game detail and tap <strong>Mark as Cancelled</strong> or <strong>Edit</strong> to change the date. Cancelled games remain on the schedule with a Cancelled badge and do not count toward your season record.</p>',14)])])}const m=a(s,[["render",i]]);export{p as __pageData,m as default};
